import 'package:fl_chart/fl_chart.dart';import 'package:flutter/material.dart';import 'package:intl/intl.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_card.dart';import '../../design_system/ds_date_range_selector.dart';import '../../design_system/ds_list_item.dart';import '../../models/category.dart';import '../../models/transaction.dart';import '../../services/mock_data_service.dart';import 'transaction_list_screen.dart';class SpendingTrendsDetailScreen extends StatefulWidget {  const SpendingTrendsDetailScreen({super.key});  @override  State<SpendingTrendsDetailScreen> createState() => _SpendingTrendsDetailScreenState();}@overrideclass _SpendingTrendsDetailScreenState extends State<SpendingTrendsDetailScreen> {  DateRange _selectedDateRange = DateRange.monthly;  DateTime _startDate = DateTime.now().subtract(const Duration(days: 30));  DateTime _endDate = DateTime.now();  List<Map<String, dynamic>> _spendingBreakdown = [];  @override  void initState() {    super.initState();    _updateSpendingData();  }  void _updateSpendingData() {    setState(() {      _spendingBreakdown =          MockDataService.getSpendingBreakdownByCategories(_startDate, _endDate);    });  }  void _onDateRangeSelected(DateRange range) {    setState(() {      _selectedDateRange = range;      switch (range) {        case DateRange.weekly:          _startDate = DateTime.now().subtract(const Duration(days: 7));          _endDate = DateTime.now();          break;        case DateRange.monthly:          _startDate = DateTime.now().subtract(const Duration(days: 30));          _endDate = DateTime.now();          break;        case DateRange.quarterly:          _startDate = DateTime.now().subtract(const Duration(days: 90));          _endDate = DateTime.now();          break;        case DateRange.custom:          // For custom, we'd typically open a date picker          // For now, let's just keep the current range or set a default          _startDate = DateTime.now().subtract(const Duration(days: 60));          _endDate = DateTime.now();          break;      }      _updateSpendingData();    });  }  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text('Spending Trends', style: AppTypography.h2),      ),      body: ListView(        padding: AppSpacing.screenPadding,        children: [          Center(            child: DsDateRangeSelector(              initialRange: _selectedDateRange,              onRangeSelected: _onDateRangeSelected,            ),          ),          SizedBox(height: AppSpacing.paddingLarge),          _buildCategoryBreakdownChart(),          SizedBox(height: AppSpacing.paddingLarge),          _buildSpendingBreakdownList(),        ],      ),    );  }  Widget _buildCategoryBreakdownChart() {    if (_spendingBreakdown.isEmpty) {      return DsCard(        child: Center(          child: Text(            'No spending data for this period.',            style: AppTypography.body.copyWith(color: AppColors.textSecondary),          ),        ),      );    }    return DsCard(      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Text('Category Breakdown', style: AppTypography.h2),          SizedBox(height: AppSpacing.paddingMedium),          SizedBox(            height: 200,            child: PieChart(              PieChartData(                sections: _spendingBreakdown.map((data) {                  final category = data['category'] as Category;                  final percentage = data['percentage'] as double;                  return PieChartSectionData(                    color: category.color,                    value: percentage * 100,                    title: percentage > 0.05                        ? '${(percentage * 100).toStringAsFixed(0)}%'                        : '',                    radius: 50,                    titleStyle: AppTypography.caption.copyWith(                      color: AppColors.buttonTextPrimary,                      fontWeight: FontWeight.bold,                    ),                    badgeWidget: percentage > 0.05                        ? _Badge(category.icon, category.color)                        : null,                    badgePositionPercentageOffset: 0.98,                  );                }).toList(),                sectionsSpace: 2,                centerSpaceRadius: 40,                startDegreeOffset: -90,                borderData: FlBorderData(show: false),                pieTouchData: PieTouchData(                  touchCallback: (FlTouchEvent event, pieTouchResponse) {                    if (pieTouchResponse != null &&                        pieTouchResponse.touchedSection != null) {                      final touchedIndex =                          pieTouchResponse.touchedSection!.touchedSectionIndex;                      final category =                          _spendingBreakdown[touchedIndex]['category'] as Category;                      ScaffoldMessenger.of(context).showSnackBar(                        SnackBar(                          content: Text(                            '${category.name}: ${MockDataService.formatCurrency(_spendingBreakdown[touchedIndex]['amount'])}',                          ),                        ),                      );                    }                  },                ),              ),            ),          ),          SizedBox(height: AppSpacing.paddingMedium),          Wrap(            spacing: AppSpacing.paddingSmall,            runSpacing: AppSpacing.paddingSmall,            children: _spendingBreakdown.map((data) {              final category = data['category'] as Category;              final percentage = data['percentage'] as double;              return Row(                mainAxisSize: MainAxisSize.min,                children: [                  Container(                    width: 10,                    height: 10,                    decoration: BoxDecoration(                      color: category.color,                      shape: BoxShape.circle,                    ),                  ),                  SizedBox(width: AppSpacing.gridBase),                  Text(                    '${category.name} (${(percentage * 100).toStringAsFixed(1)}%)',                    style: AppTypography.caption,                  ),                ],              );            }).toList(),          ),        ],      ),    );  }  Widget _buildSpendingBreakdownList() {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Text('Spending Breakdown', style: AppTypography.h2),        SizedBox(height: AppSpacing.paddingMedium),        DsCard(          padding: EdgeInsets.zero,          child: Column(            children: _spendingBreakdown.map((data) {              final category = data['category'] as Category;              final amount = data['amount'] as double;              final percentage = data['percentage'] as double;              return DsListItem(                leading: Container(                  width: AppSpacing.categoryIconSize,                  height: AppSpacing.categoryIconSize,                  decoration: BoxDecoration(                    color: category.color.withOpacity(0.2),                    borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),                  ),                  child: Icon(category.icon, color: category.color),                ),                title: category.name,                subtitle: '${(percentage * 100).toStringAsFixed(1)}% of total',                trailingText: MockDataService.formatCurrency(amount),                trailingTextColor: AppColors.error,                onTap: () {                  Navigator.of(context).push(MaterialPageRoute(                    builder: (_) => TransactionListScreen(                      title: '${category.name} Transactions',                      transactions: MockDataService.getTransactionsForCategory(category),                    ),                  ));                },              );            }).toList(),          ),        ),      ],    );  }}class _Badge extends StatelessWidget {  const _Badge(this.icon, this.color);  final IconData icon;  final Color color;  @override  Widget build(BuildContext context) {    return AnimatedContainer(      duration: PieChart.defaultDuration,      width: 40,      height: 40,      decoration: BoxDecoration(        color: color.withOpacity(0.2),        shape: BoxShape.circle,        border: Border.all(color: color, width: 1),      ),      child: Center(        child: Icon(icon, color: color, size: 20),      ),    );  }}